import { useState } from 'react';
import { Link, useNavigate, useParams } from 'react-router-dom';

import constFlaskURL from '../../consts/constFlaskURL'

import '../../App.css';
import '../../../node_modules/bootstrap/dist/css/bootstrap.css'


function EditLocalityCrossroad() {
    const [crossroad_road_sing_id, setCrossroadRoadSingID] = useState('');
    const [locality_id, setLocalityID] = useState('');
    const [loading, setLoading] = useState(false);
    const navigate = useNavigate();
    const { id } = useParams();

      const handleLogout = async () => {
        setLoading(true);

        try {
            const response = await constFlaskURL.post('/logout');

            if (response.status === 200) {
                setTimeout(() => {
                    navigate('/login');
                }, 1000);
            }
        } catch (err) {
            console.error('Logout error:', err);
        } 
        finally {
            setLoading(false);
        }
    };

    const submitLocalityCrossroad = async (e) => {
        e.preventDefault();
        const crossroad_road_sing = { crossroad_road_sing_id, locality_id };

        try {
            const add_locality_crossroad = await constFlaskURL.put(`/localities/crossroads?id=${id}`, crossroad_road_sing, {
                headers: {
                    'Content-Type': 'multipart/form-data',
                    'Accept': 'application/json'
                }
            });

            if (add_locality_crossroad.status === 200){
                setCrossroadRoadSingID('');
                setLocalityID('');
                navigate('/localities/crossroads');
            }
        } catch (error) {
            console.log(error);
        }
    };

    return (
        <div>
            <nav className="navbar navbar-expand-lg navbar-dark bg-dark flex-column align-items-start p-0">
                <div className="container-fluid py-2">
                    <Link className="navbar-brand fs-3 fw-bold" to="/main">roads_admin</Link>
                    <div class="btn-group">
                        <button type="button" class="btn btn-info">Пользователь</button>
                        <button type="button" class="btn btn-info dropdown-toggle dropdown-toggle-split" data-bs-toggle="dropdown" aria-expanded="false">
                            <span class="visually-hidden">Переключатель выпадающего списка</span>
                        </button>
                        <ul class="dropdown-menu">
                            <li>
                                <a class="dropdown-item">
                                    <button
                                        onClick={handleLogout} 
                                        className='dropdown-item'
                                        disabled={loading}
                                    >
                                        {loading ? (
                                            <>
                                                <span className='spinner'></span>
                                                Выход...
                                            </>
                                        ) : 'Выйти'}
                                    </button>
                                </a>
                            </li>
                        </ul>
                    </div>
                </div>
            </nav>
            <form className='container' onSubmit={submitLocalityCrossroad}>
                <h1>Создание знака на населенном пункте</h1>
                <div className='mb-3'>
                    <lable className='form-label'>ID дорожного знака на перекрестке</lable>
                    <input 
                        type='text'
                        name='crossroad_road_sing_id' 
                        value={crossroad_road_sing_id.crossroad_road_sing_id} 
                        onChange={(e) => setRoadSingID(e.target.value)}
                        className='form-input'  
                        placeholder='ID дорожного знака на перекрестке'
                        required  
                    />
                </div>
                <div className='mb-3'>
                    <lable className='form-label'>ID населенного пункта</lable>
                    <input 
                        type='text'
                        name='locality_id' 
                        value={locality_id.locality_id} 
                        onChange={(e) => setCrossroadID(e.target.value)}
                        className='form-input'  
                        placeholder='ID населенного пункта'
                        required  
                    />
                </div>
                <button 
                    type='submit' 
                    className='btn btn-primary'
                >
                    Сохранить
                </button>
                <button 
                    type='submit' 
                    className='btn btn-danger' 
                    onClick={() => navigate('/localities/crosseoads')}
                >
                    Назад
                </button>
            </form>
        </div>
    )
};

export default EditLocalityCrossroad;
